// ===== CHESS HV3 EXTENSIONS =====

// 1. DYNAMIC HOTKEY SYSTEM (semua toggle)
(function() {
  const TOGGLE_MAP = {
    hotkeyAutoMove:    { config: 'autoMove',         label: 'Auto Move' },
    hotkeyBalanced:    { config: 'autoMoveBalanced', label: 'Balanced Auto Move' },
    hotkeyAutoStart:   { config: 'autoStart',        label: 'Auto Start Game' },
    hotkeyReview:      { config: 'review',           label: 'ChessHv3 Check' },
    hotkeyStat:        { config: 'stat',             label: 'Display Accuracy' },
    hotkeyWinningMove: { config: 'winningMove',      label: 'Only Winning Moves' },
    hotkeyShowEval:    { config: 'showEval',         label: 'Show Eval Bar' },
    hotkeyHideArrows:  { config: 'onlyShowEval',     label: 'Hide Arrows' },
    hotkeyAutoSpeedUp: { config: 'autoSpeedUp',      label: 'Auto Speed Up' },
  };

  function showToast(msg, bottom) {
    const id = '__hkToast__';
    const existing = document.getElementById(id);
    if (existing) existing.remove();
    const t = document.createElement('div');
    t.id = id;
    t.textContent = msg;
    t.style.cssText = `position:fixed;bottom:${bottom||30}px;right:30px;background:rgba(0,0,0,0.85);
      color:#fff;font-size:15px;font-weight:bold;padding:10px 22px;border-radius:8px;
      z-index:99999;pointer-events:none;transition:opacity 0.4s;`;
    document.body.appendChild(t);
    setTimeout(() => { t.style.opacity = '0'; }, 1800);
    setTimeout(() => { t.remove(); }, 2300);
  }

  document.addEventListener('keydown', function(e) {
    const tag = document.activeElement ? document.activeElement.tagName : '';
    if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return;
    chrome.storage.local.get(['chessConfig'], function(result) {
      const cfg = result.chessConfig || {};
      for (const [hotkeyKey, info] of Object.entries(TOGGLE_MAP)) {
        const hotkey = cfg[hotkeyKey] || '';
        if (!hotkey) continue;
        if (e.key.toLowerCase() === hotkey.toLowerCase()) {
          cfg[info.config] = !cfg[info.config];
          chrome.storage.local.set({ chessConfig: cfg }, function() {
            showToast(info.label + ': ' + (cfg[info.config] ? '✅ ON' : '❌ OFF'));
          });
          e.preventDefault();
          break;
        }
      }
    });
  });
})();

// 2. DELAY PATCH (random delay + auto speed up)
(function() {
  function parseTimeToSeconds(txt) {
    if (!txt) return null;
    const parts = txt.split(':');
    if (parts.length === 2) return parseInt(parts[0]) * 60 + parseFloat(parts[1]);
    return parseFloat(txt);
  }

  function getMyClockSeconds() {
    const el =
      document.querySelector('.clock-component.clock-bottom span[data-cy="clock-time"]') ||
      document.querySelector('.clock-component.clock-bottom .clock-time-monospace') ||
      document.querySelector('.rclock-bottom .time');
    return el ? parseTimeToSeconds(el.textContent.trim()) : null;
  }

  function getDelayMultiplier(s) {
    if (s === null) return 1;
    if (s < 10) return 0.05;
    if (s < 30) return 0.25;
    if (s < 60) return 0.5;
    return 1;
  }

  function computeDelay(cfg) {
    const mn = typeof cfg.delayMin === 'number' ? cfg.delayMin : 200;
    const mx = typeof cfg.delayMax === 'number' ? cfg.delayMax : 800;
    let lo = mn, hi = mx;
    if (cfg.autoSpeedUp) {
      const m = getDelayMultiplier(getMyClockSeconds());
      lo = Math.floor(mn * m);
      hi = Math.floor(mx * m);
    }
    hi = Math.max(lo, hi);
    return Math.floor(Math.random() * (hi - lo + 1)) + lo;
  }

  const _get = chrome.storage.local.get.bind(chrome.storage.local);
  chrome.storage.local.get = function(keys, callback) {
    _get(keys, function(result) {
      if (result && result.chessConfig) {
        result.chessConfig.delay = computeDelay(result.chessConfig);
      }
      callback(result);
    });
  };
})();

// 3. MINI HUD
(function() {
  let hudVisible = true;

  function createHUD() {
    if (document.getElementById('__chessHUD__')) return;
    const hud = document.createElement('div');
    hud.id = '__chessHUD__';
    hud.style.cssText = `position:fixed;top:80px;right:12px;background:rgba(15,15,15,0.92);
      color:#fff;font-size:12px;font-family:monospace;border-radius:8px;
      border:1px solid rgba(255,255,255,0.15);z-index:99998;min-width:165px;
      box-shadow:0 4px 16px rgba(0,0,0,0.5);user-select:none;`;

    const header = document.createElement('div');
    header.style.cssText = `display:flex;align-items:center;justify-content:space-between;
      padding:5px 10px;background:rgba(255,255,255,0.07);border-radius:8px 8px 0 0;
      cursor:pointer;font-weight:bold;font-size:11px;letter-spacing:1px;color:#aaa;`;
    header.innerHTML = `<span>♟ ChessHv3</span><span id="__hudToggleBtn__" style="font-size:14px">−</span>`;

    const body = document.createElement('div');
    body.id = '__hudBody__';
    body.style.cssText = `padding:8px 10px;display:flex;flex-direction:column;gap:4px;`;

    hud.appendChild(header);
    hud.appendChild(body);
    document.body.appendChild(hud);

    header.addEventListener('click', () => {
      hudVisible = !hudVisible;
      body.style.display = hudVisible ? 'flex' : 'none';
      document.getElementById('__hudToggleBtn__').textContent = hudVisible ? '−' : '+';
    });
  }

  function getClockText() {
    const el =
      document.querySelector('.clock-component.clock-bottom span[data-cy="clock-time"]') ||
      document.querySelector('.clock-component.clock-bottom .clock-time-monospace') ||
      document.querySelector('.rclock-bottom .time');
    return el ? el.textContent.trim() : '—';
  }

  function dot(val) {
    return val ? '<span style="color:#2ecc71">●</span>' : '<span style="color:#444">●</span>';
  }

  function btn(id, color, label) {
    return `<button id="${id}" style="background:${color};border:none;color:#fff;font-weight:bold;
      font-size:11px;border-radius:4px;padding:1px 7px;cursor:pointer;line-height:1.6">${label}</button>`;
  }

  function updateHUD() {
    const body = document.getElementById('__hudBody__');
    if (!body || !hudVisible) return;
    chrome.storage.local.get(['chessConfig'], function(result) {
      const cfg = result.chessConfig || {};
      const mn = cfg.delayMin ?? 200;
      const mx = cfg.delayMax ?? 800;
      body.innerHTML = `
        <div style="display:flex;justify-content:space-between"><span style="color:#888">Auto Move</span>${dot(cfg.autoMove)}</div>
        <div style="display:flex;justify-content:space-between"><span style="color:#888">Balanced</span>${dot(cfg.autoMoveBalanced)}</div>
        <div style="display:flex;justify-content:space-between"><span style="color:#888">Speed Up</span>${dot(cfg.autoSpeedUp)}</div>
        <div style="display:flex;justify-content:space-between"><span style="color:#888">Show Eval</span>${dot(cfg.showEval)}</div>
        <div style="display:flex;justify-content:space-between"><span style="color:#888">Hide Arrows</span>${dot(cfg.onlyShowEval)}</div>
        <div style="border-top:1px solid rgba(255,255,255,0.08);margin:3px 0"></div>
        <div style="color:#aaa;font-size:10px">Min Delay</div>
        <div style="display:flex;align-items:center;justify-content:space-between;gap:4px">
          ${btn('__hudMn-__','#c0392b','−100')}
          <span id="__hudMnV__" style="color:#f1c40f;min-width:52px;text-align:center">${mn}ms</span>
          ${btn('__hudMn+__','#27ae60','+100')}
        </div>
        <div style="color:#aaa;font-size:10px;margin-top:2px">Max Delay</div>
        <div style="display:flex;align-items:center;justify-content:space-between;gap:4px">
          ${btn('__hudMx-__','#c0392b','−100')}
          <span id="__hudMxV__" style="color:#f1c40f;min-width:52px;text-align:center">${mx}ms</span>
          ${btn('__hudMx+__','#27ae60','+100')}
        </div>
        <div style="border-top:1px solid rgba(255,255,255,0.08);margin:3px 0"></div>
        <div style="display:flex;justify-content:space-between"><span style="color:#888">Clock</span><span style="color:#3498db">${getClockText()}</span></div>
        <div style="display:flex;justify-content:space-between"><span style="color:#888">ELO</span><span style="color:#e67e22">${cfg.elo??3500}</span></div>
      `;

      function adj(key, delta) {
        chrome.storage.local.get(['chessConfig'], function(r) {
          const c = r.chessConfig || {};
          c[key] = Math.max(0, (c[key] ?? (key==='delayMin'?200:800)) + delta);
          if (key==='delayMin' && c.delayMin > c.delayMax) c.delayMax = c.delayMin;
          if (key==='delayMax' && c.delayMax < c.delayMin) c.delayMin = c.delayMax;
          c.delay = c.delayMax;
          chrome.storage.local.set({ chessConfig: c }, updateHUD);
        });
      }

      document.getElementById('__hudMn-__')?.addEventListener('click', e => { e.stopPropagation(); adj('delayMin',-100); });
      document.getElementById('__hudMn+__')?.addEventListener('click', e => { e.stopPropagation(); adj('delayMin',+100); });
      document.getElementById('__hudMx-__')?.addEventListener('click', e => { e.stopPropagation(); adj('delayMax',-100); });
      document.getElementById('__hudMx+__')?.addEventListener('click', e => { e.stopPropagation(); adj('delayMax',+100); });
    });
  }

  function init() {
    createHUD();
    updateHUD();
    setInterval(updateHUD, 1000);
  }

  if (document.readyState === 'complete' || document.readyState === 'interactive') {
    setTimeout(init, 1500);
  } else {
    document.addEventListener('DOMContentLoaded', () => setTimeout(init, 1500));
  }
})();
